import{_ as t,c as a,o,a5 as i}from"./chunks/framework.CgT1UzWm.js";const n="/ddd-agggrate-transparent.webp",u=JSON.parse('{"title":"DRAFT: 20th Anniversary of The Vietnam of Computer Science","titleTemplate":"NpgsqlRest","description":"DRAFT — A compilation of a decade of arguments about DDD, Clean Architecture, the wrong abstractions modern business software is built on, and the case for putting the database back where it belongs.","frontmatter":{"layout":"doc","outline":[2,3],"title":"DRAFT: 20th Anniversary of The Vietnam of Computer Science","titleTemplate":"NpgsqlRest","description":"DRAFT — A compilation of a decade of arguments about DDD, Clean Architecture, the wrong abstractions modern business software is built on, and the case for putting the database back where it belongs.","badge":"human","head":[["meta",{"name":"robots","content":"noindex, nofollow"}],["meta",{"name":"keywords","content":"npgsqlrest postgresql clean architecture ddd database-first state abstraction sql platform business rules"}]]},"headers":[],"relativePath":"blog/DRAFT-anniversary-vietnam-of-computer-science.md","filePath":"blog/DRAFT-anniversary-vietnam-of-computer-science.md"}'),s={name:"blog/DRAFT-anniversary-vietnam-of-computer-science.md"};function r(l,e,h,c,d,m){return o(),a("div",null,e[0]||(e[0]=[i('<h1 id="draft-20th-anniversary-of-the-vietnam-of-computer-science" tabindex="-1">DRAFT: 20th Anniversary of The Vietnam of Computer Science <a class="header-anchor" href="#draft-20th-anniversary-of-the-vietnam-of-computer-science" aria-label="Permalink to &quot;DRAFT: 20th Anniversary of The Vietnam of Computer Science&quot;">​</a></h1><p class="blog-meta"><span>DRAFT — TODO: date</span> · <span class="tag">NpgsqlRest</span><span class="tag">PostgreSQL</span><span class="tag">Architecture</span><span class="tag">DDD</span><span class="tag">Clean Architecture</span><span class="tag">Opinion</span></p><p><img src="https://img.shields.io/badge/Human-Written-blue" alt=""><img src="https://img.shields.io/badge/DRAFT-orange" alt=""></p><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>It has been 20 years since Ted Neward published his famous article <a href="https://www.odbms.org/wp-content/uploads/2013/11/031.01-Neward-The-Vietnam-of-Computer-Science-June-2006.pdf" target="_blank" rel="noreferrer">&quot;The Vietnam of Computer Science&quot;</a>. It is officially old enough to get a drink and own a car.</p><p>But funny thing is, we happily kept fighting the same unwinnable war ever since. I feel like we didnt even tried. So I decided to write my own essay on the topic and see to how really deep this Object–Relational Impedance Mismatch rabbit hole really is.</p><p>Before I start, I want to make a couple of things clear.</p><p>First, the term <strong>Object–Relational Impedance Mismatch</strong>, and that is what that article is really about, appears to be pretty old. It goes way back to the 80s, and it is not even clear who coined it. At least, I couldn&#39;t find any definitive source on that.</p><p>Secondly, that article, the others on this topic, as well as the countless online discussions - all seem to center around one specific thing: the O/R tools, or simply ORMs. That makes sense in a way. I mean, if we have an O/R mismatch, then certainly the O/R tools are to blame, right? They are the ones supposed to bridge that gap between objects and relations (hint: they never did).</p><p>O/R tools do have their own set of problems and that is a sligthly different topic for me. The problem, in my opinion, is much, much deeper than that.</p><p>It is the modern orthodoxy, if you will. The way we do things. To be blunt: the core of the problem lies in modern approaches to software design and architecture — Domain-Driven Design (DDD), Clean Architecture (CA), and the derivatives (Onion, Hexagonal, etc.). At least, how they are implemented by the followers. They are all built on the same principles. Even the number of different names of the roughly same approach should tell you something.</p><p>Anyway, if you are willing to question things and open-minded enought - keep reading.</p><hr><h2 id="what-is-the-object–relational-impedance-mismatch" tabindex="-1">What Is The Object–Relational Impedance Mismatch <a class="header-anchor" href="#what-is-the-object–relational-impedance-mismatch" aria-label="Permalink to &quot;What Is The Object–Relational Impedance Mismatch&quot;">​</a></h2><p>According to Wikipedia (link: <a href="https://en.wikipedia.org/wiki/Object%E2%80%93relational_impedance_mismatch" target="_blank" rel="noreferrer">https://en.wikipedia.org/wiki/Object–relational_impedance_mismatch</a>):</p><blockquote><p>Object–relational impedance mismatch is a <strong>set of difficulties</strong> going between data in relational data stores and data in domain-driven object models.</p></blockquote><p>Ok, got it. A set of difficulties. Difficulties that refuse to go away, it seems, but fine.</p><p>It is important to note here that Object–relational impedance mismatch is not the only relational mismatch we can have. Since today object-oriented (OO) programming is not the only thing we have nowadays, there is also functional programming (FP), which is getting pretty popular, and therefore we can also have Functional impedance mismatch. But more on that later.</p><blockquote><p>Relational Database Management Systems (RDBMS) is the standard method for storing data in a dedicated database, while object-oriented (OO) programming is the default method for business-centric design in programming languages.</p></blockquote><p>RDBMS is the standard method for storing data in a dedicated database, but are they typically doing only data storage? I mean, files are also doing that, are they not? Are we missing something here?</p><p>And this second claim that object-oriented (OO) programming is the default method for business-centric design, that might be true, but SQL is the default method for anything business data-related, like the way organizations store, manage, protect, and analyze their data.</p><p>We can see the tension already here, but let&#39;s move on.</p><blockquote><p>The problem lies in neither relational databases nor OO programming, but in the conceptual difficulty mapping between the <strong>two logic models</strong>. <strong>Both logical models</strong> are differently implementable using database servers, programming languages, design patterns, or other technologies.</p></blockquote><p>Now, why would they say that we have two logical models?</p><p>We all agree that a system can have one conceptual model, right? At least, when we talk about the same bounded context. Two conceptual models in the same bounded context wouldn&#39;t make any sense. And a logical model is derived from that unified conceptual model, but just more specific about data-wise. But the logical model is also devoid of any implementation details, hence the name - logical model. And then we use the logical model to produce concrete implementations - physical models. So, for example, the logical model can say that some data is text type and belongs to an entity. But in physical model implementation, that type will become maybe <code>varchar(255)</code> in a table or a <code>string</code> property in a class.</p><p>So, in a case of modern software design, we are not talking about two different logical models as Wikipedia claims. We have one logical model and two different physical models. Or, at least two, sometimes even more. Modern overengineering knows no bounds.</p><p>The reason why they say that we have two logical models is probably because OO and Relational are seen a totally different paradigms so the logical models must be genuinely different. For example OO does have behavior, but problem is that we are talking strictly about data here, not behavior.</p><p>In any case, impedance mismatch is not about two different logical models, but about the mismatch between those two physical models. Your system has to map them and make them work together because, logically, we still have one logical model and the system needs to reflect that. That’s the real problem and source of tension.</p><blockquote><p>Issues range from application to enterprise scale, whenever stored relational data is used in domain-driven object models, and vice versa. Object-oriented data stores can trade this problem for other implementation difficulties.</p></blockquote><p>This last sentence just confirms what I just said. Whenever stored relational data (one physical model) is used in domain-driven object models (another physical model), we have this problem or mismatch. Maybe the belief that we are talking about two different logical models is the reason why these difficulties exist and persist and are not being resolved. If it was just a simple mapping, let&#39;s say from <code>varchar(255)</code> to a <code>string</code>, that would be easy to solve a long time ago. Or something a bit more complex, let&#39;s say many-to-many on a logical model level. In a relational model, that requires a junction table, but in an object model that can be just a collection of references. Still, a little bit more complex mapping, but still solvable and indeed already solved.</p><p>My sincere belief is that we are talking here about a series of misconceptions and misunderstandings about the nature of abstractions themselves. To be more specific, specifically, about abstractions the RDBMS already provides. And if RDBMS already provides them, well, that means that the application layer goes on and re-implements them anyway. No wonder we have difficulties. Let&#39;s look at these misconceptions one by one and discuss in details:</p><ol><li><p><strong>State Data</strong> Abstraction Misconception</p></li><li><p><strong>Storage Devices</strong> Abstraction Misconception</p></li><li><p><strong>Data Structures</strong> Abstraction Misconception</p></li><li><p>Abstraction Over <strong>Algorithms</strong></p></li><li><p>Abstraction Over <strong>Concurrency and Integrity</strong></p></li></ol><h2 id="_1-state-data-abstraction-misconception" tabindex="-1">1) State Data Abstraction Misconception <a class="header-anchor" href="#_1-state-data-abstraction-misconception" aria-label="Permalink to &quot;1) State Data Abstraction Misconception&quot;">​</a></h2><h2 id="_1-state-data-abstraction-misconception-1" tabindex="-1">1) State Data Abstraction Misconception <a class="header-anchor" href="#_1-state-data-abstraction-misconception-1" aria-label="Permalink to &quot;1) State Data Abstraction Misconception&quot;">​</a></h2><h3 id="the-claim" tabindex="-1">The Claim <a class="header-anchor" href="#the-claim" aria-label="Permalink to &quot;The Claim&quot;">​</a></h3><p>Object-oriented programming has one of its core tenets called <strong>encapsulation</strong>. Encapsulation is supposed to protect internal data — <strong>the state</strong>. The object is the authoritative custodian of its state. Nobody else has it. Period. Without encapsulation, we don&#39;t really have OOP anymore.</p><p>On the other hand, functional programming has its own version of that — <strong>state immutability</strong>. A function takes values in and returns new values out, leaving the originals untouched — so there&#39;s no shared mutable state to corrupt in the first place. FP also enforces valid state through invariants, often by encoding them directly into the type system. Same goal, fewer bugs from uncontrolled state, arguably reached more elegantly. Fine. State status - protected, bugs - reduced. Great, beautiful.</p><p>This, in fact, is very reasonable and well-thought-out. State data is data shared between different parts of the system and even different users. If every part of the system can poke at it without other parts knowing about it, then you have a lot of bugs. So, naturally, over time we came up with these concepts of encapsulation and immutability to protect that state and make sure it is only changed and fiddled with in a controlled way. Because we don&#39;t want to have bugs. Bugs are bad.</p><p>No objection here. This is perfectly fine, and it makes a lot of sense. Let&#39;s say we have something complex. A game scene. Compiler syntax tree. Whatever. Protecting state in memory of such systems is invaluable, at least.</p><p>In his book Domain-Driven Design (2004), when describing the Domain Layer in Chapter 4, &quot;Isolating the Domain,&quot; Eric Evans writes:</p><blockquote><p>State that reflects the business situation is controlled and used here, even though the technical details of storing it are delegated to the infrastructure.</p></blockquote><p>So he treats the in-memory object as the custodian of state - state that is &quot;controlled and used here,&quot; where &quot;here&quot; is the in-memory Domain Layer — while the RDBMS is merely &quot;delegated to the infrastructure.&quot; More on that in the next chapter. What matters here is the claim itself: the state is in memory. No doubt about it.</p><h3 id="the-reality" tabindex="-1">The Reality <a class="header-anchor" href="#the-reality" aria-label="Permalink to &quot;The Reality&quot;">​</a></h3><p>But what about applications backed by relational databases, business or otherwise?</p><p>In RDBMS-backed applications, the state lives in that RDBMS itself - not in memory. The authoritative custodian of state is the <strong>database table row</strong>, not the in-memory object.</p><p>Take any business application backed by a relational database. How do you check the current state of some entity? Do you peek at the object in memory? No, you query the database for that. Anyone who has worked 5 seconds in industry knows this, of course.</p><p>I know what DDD people will say now: object memory (or functional state memory) is the real state data, and RDBMS is just where that data is persisted (presumably when the user clicks on a &quot;Save&quot; icon).</p><p>Eric Evans himself, in his blue book on DDD, says:</p><blockquote><p>For each type of object that needs global access, create an object that can provide the <strong>illusion of an in-memory collection</strong> of all objects of that type.</p></blockquote><p>He is basically admitting that the memory collection is an illusion, not even real, and concedes that memory isn’t the real state.</p><p>And, if you still believe that objects/memory are the real state and not RDBMS, then riddle me this:</p><p>What if we have multiple instances of the application running behind a load balancer? And then maybe some background work as well, and some other services too. Maybe reporting replica as well, so we have multiple processes accessing the same state data. Who is the sole custodian of that state data in that case? The in-memory object of one process, or the database row? The obvious answer is, of course, NONE of the in-memory copies. The best we can do is to have each process hold a copy, while the real state is in the RDBMS itself.</p><p>I know what some may say now, but databases have multiplicity too, right? We have multiple replicas, and they are all copies of the same data. And there are also multi-master setups as well with multiple writers for high availability scenarios. Yeah, but the big difference is that the database solves it, while in-memory objects don&#39;t even try. They just deny the reality. For multiple replicas, there is never any ambiguity about which one is the source of truth, since we are talking about read-only copies, and for multi-master setups we have either different consensus protocols that ensure a single source of truth or so-called eventual-consistency for the source of truth. In-memory objects have no such machinery, so they just pretend that they are the single custodian of the state data, which is, of course, a big, fat lie.</p><p>Also, if the object is the custodian of state, what if we kill and restart the application? Oh my, the object&#39;s custodianship has evaporated.</p><p>Also, what, for example, if we have two concurrent user writers? One loads an invoice as &#39;pending&#39;, but another writer marks it &#39;paid&#39; while the first one holds it. Now the first one is lying about the state of that invoice. The database is right - it is the source of truth - the first one is stale. We will talk more about concurrency and integrity later - this is just to prove my point:</p><p>RDBMS is the authoritative custodian of state, not in-memory objects. The state lives in the database, not in memory.</p><h3 id="the-cost" tabindex="-1">The Cost <a class="header-anchor" href="#the-cost" aria-label="Permalink to &quot;The Cost&quot;">​</a></h3><p>Take a look at this example of a DDD-style domain model below:</p><figure style="margin:0;text-align:center;"><img src="'+n+'" alt="" style="display:block;width:50%;max-width:100%;height:auto;margin:0 auto;"><figcaption style="font-size:0.8em;color:#888;margin-top:0.5em;"> Source credit: <a href="https://www.reddit.com/r/DomainDrivenDesign/comments/1ttzr19/create_complex_and_deep_aggregate/">https://www.reddit.com/r/DomainDrivenDesign/comments/1ttzr19/create_complex_and_deep_aggregate/</a></figcaption></figure><p>This is a random example from Reddit, but it is indicative. Virtually every domain model is more or less like that - strip away the method, adjust types a bit, and it is basically an Entity-Relationship (ER) diagram, that&#39;s it. There is no structural difference between the domain model and the database model. It is the same logical model implemented twice.</p><p>And that method <code>isValid()</code>, the only behavior in that domain model, is basically a data integrity check. It is the same check that the database can do with a <code>CHECK</code> constraint. So we have the same logical model implemented twice, and the same integrity check implemented twice as well.</p><p>Because modern software design orthodoxy refuses to acknowledge that the state lives in the RDBMS, it forces us to implement the same model at least twice - once in the database (relational model implementation), once one in memory (object model implementation, mapped usually with an O/R tool or a library).</p><p>I say at least, because there are examples where we have even more. Some &quot;architects&quot; will consider that O/R mapped model a persistence model because it doesn&#39;t have any behavior, and then they will add a separate domain model on top of that, which is the one with the behavior. So we have three implementations of the same logical model - database model, persistence model, and domain model.</p><p>And then, since we now have at least two physical models, we also have two type systems and two sets of constraints to protect the state. And we must keep them in sync at all times, and we must maintain the correct mapping. To be fair, this is mostly automated in modern systems (not completely), but we still have to do it and it is still there, automated or not. And even automated, it is still a cost and still a source of bugs and still a source of complexity. And even that can&#39;t bridge the semantic gap between the two type systems fully. For example, in PostgreSQL we can have a <code>NOT NULL</code> constraint on a column, but the corresponding C# property will be a nullable string.</p><p>All because we believe that there is some important state data we need to protect with our objects. In the best case, there are just some transient and disposable chunks of data copies, and in any case there is a lot of plumbing to manage: connections, transactions, commands, queries, etc. You know, the actual infrastructure.</p><p>Personally, I see a lot of irony in this. Modern orthodoxy calls RDBMS infrastructure, just to end up with code bases implementing, well, actual infrastructure.</p><h2 id="_2-storage-devices-abstraction-misconception" tabindex="-1">2) Storage Devices Abstraction Misconception <a class="header-anchor" href="#_2-storage-devices-abstraction-misconception" aria-label="Permalink to &quot;2) Storage Devices Abstraction Misconception&quot;">​</a></h2><h3 id="the-claim-1" tabindex="-1">The Claim <a class="header-anchor" href="#the-claim-1" aria-label="Permalink to &quot;The Claim&quot;">​</a></h3><h3 id="the-reality-1" tabindex="-1">The Reality <a class="header-anchor" href="#the-reality-1" aria-label="Permalink to &quot;The Reality&quot;">​</a></h3><h3 id="the-cost-1" tabindex="-1">The Cost <a class="header-anchor" href="#the-cost-1" aria-label="Permalink to &quot;The Cost&quot;">​</a></h3><h2 id="_3-data-structures-abstraction-misconception" tabindex="-1">3) Data Structures Abstraction Misconception <a class="header-anchor" href="#_3-data-structures-abstraction-misconception" aria-label="Permalink to &quot;3) Data Structures Abstraction Misconception&quot;">​</a></h2><h3 id="the-claim-2" tabindex="-1">The Claim <a class="header-anchor" href="#the-claim-2" aria-label="Permalink to &quot;The Claim&quot;">​</a></h3><h3 id="the-reality-2" tabindex="-1">The Reality <a class="header-anchor" href="#the-reality-2" aria-label="Permalink to &quot;The Reality&quot;">​</a></h3><h3 id="the-cost-2" tabindex="-1">The Cost <a class="header-anchor" href="#the-cost-2" aria-label="Permalink to &quot;The Cost&quot;">​</a></h3><h2 id="_4-abstraction-over-algorithms" tabindex="-1">4) Abstraction Over Algorithms <a class="header-anchor" href="#_4-abstraction-over-algorithms" aria-label="Permalink to &quot;4) Abstraction Over Algorithms&quot;">​</a></h2><h3 id="the-claim-3" tabindex="-1">The Claim <a class="header-anchor" href="#the-claim-3" aria-label="Permalink to &quot;The Claim&quot;">​</a></h3><h3 id="the-reality-3" tabindex="-1">The Reality <a class="header-anchor" href="#the-reality-3" aria-label="Permalink to &quot;The Reality&quot;">​</a></h3><h3 id="the-cost-3" tabindex="-1">The Cost <a class="header-anchor" href="#the-cost-3" aria-label="Permalink to &quot;The Cost&quot;">​</a></h3><h2 id="_5-abstraction-over-concurrency-and-integrity" tabindex="-1">5) Abstraction Over Concurrency and Integrity <a class="header-anchor" href="#_5-abstraction-over-concurrency-and-integrity" aria-label="Permalink to &quot;5) Abstraction Over Concurrency and Integrity&quot;">​</a></h2><h3 id="the-claim-4" tabindex="-1">The Claim <a class="header-anchor" href="#the-claim-4" aria-label="Permalink to &quot;The Claim&quot;">​</a></h3><h3 id="the-reality-4" tabindex="-1">The Reality <a class="header-anchor" href="#the-reality-4" aria-label="Permalink to &quot;The Reality&quot;">​</a></h3><h3 id="the-cost-4" tabindex="-1">The Cost <a class="header-anchor" href="#the-cost-4" aria-label="Permalink to &quot;The Cost&quot;">​</a></h3><h2 id="the-good-parts" tabindex="-1">The Good Parts <a class="header-anchor" href="#the-good-parts" aria-label="Permalink to &quot;The Good Parts&quot;">​</a></h2><h2 id="how-the-hell-we-got-here" tabindex="-1">How The Hell We Got Here <a class="header-anchor" href="#how-the-hell-we-got-here" aria-label="Permalink to &quot;How The Hell We Got Here&quot;">​</a></h2><h2 id="current-state-of-affairs" tabindex="-1">Current State of Affairs <a class="header-anchor" href="#current-state-of-affairs" aria-label="Permalink to &quot;Current State of Affairs&quot;">​</a></h2><h2 id="my-solution" tabindex="-1">My Solution <a class="header-anchor" href="#my-solution" aria-label="Permalink to &quot;My Solution&quot;">​</a></h2><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h2>',87)]))}const b=t(s,[["render",r]]);export{u as __pageData,b as default};
